<template>
    <div>
        <v-dialog @input="closeDialog()" v-bind:value="dialogVisibility">
            <v-card>
                <v-card-title>Inserisci il seguente numero {{challenge}}</v-card-title>
                <v-card-text>
                    <v-text-field
                        v-model="reply"
                        type="number"
                        label="0123456789"
                        v-bind:error="is_captcha_wrong"
                    >

                    </v-text-field>
                    <v-toolbar flat>
                        <v-spacer></v-spacer>
                        <v-btn v-bind:loading="isLoading" @click="send()">Invia</v-btn>
                    </v-toolbar>
                </v-card-text>
            </v-card>
        </v-dialog>
        <v-btn @click="recaptcha()" text small>
            <v-icon id="icon">{{checkbox_icon}}</v-icon>
            Non sono un robot*
        </v-btn>
    </div>
</template>

<script>
export default {
    data () {
        return {
            reply: null,
            dialogVisibility: false,
            challenge: null,
            isLoading: false,
            checkbox_icon: 'mdi-checkbox-blank-outline',
            is_captcha_wrong: false
        }
    },
    methods: {
        sleep(ms) {
            return new Promise(resolve => setTimeout(resolve, ms));
        },
        async buttonAnimation(ms) {
            this.isLoading = true
            await this.sleep(ms)
            this.isLoading = false
        },
        randomNumber() {
            return Math.ceil(Math.random() * 10000)
        },
        async send () {
            this.buttonAnimation(2000)
            if (this.challenge + '' === this.reply) {
                this.checkbox_icon = 'mdi-checkbox-marked-outline'
                this.closeDialog()
                this.$emit('captchaResult', true)
            } else {
                this.is_captcha_wrong = true
                setTimeout(() => {
                    this.is_captcha_wrong = false
                }, 2500);
            }
        },
        closeDialog() {
            this.reply = null
            this.dialogVisibility = false
        },
        recaptcha() {
            this.dialogVisibility = true
            this.challenge = this.randomNumber()
        },
    }
}
</script>